+export function _resolveRecur<TValue>(value: TValue): TValue {
+  const references = new Map<object, object>();
+
+  function resolve<TItem>(item: TItem, root?: object): TItem {
+    if (item === Recur) {
+      return root as TItem;
+    }
+    if (typeof item !== 'object' || item === null) {
+      return item;
+    }
+
+    const existing = references.get(item);
+    if (existing) {
+      return existing as TItem;
+    }
+
+    const clone = Array.isArray(item)
+      ? []
+      : Object.create(Object.getPrototypeOf(item));
+    references.set(item, clone);
+
+    for (const key of Reflect.ownKeys(item)) {
